import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtExecutableReference;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.CtScanner;

public class Main {
    public static void main(String[] args) {
        // Generic transformation for fixing Bouncy Castle TLS API changes
        // This fixes the removal of org.bouncycastle.crypto.tls package in version 1.67+

        if (args.length < 1) {
            System.err.println("Usage: Main <source-directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        // Create a launcher to process the code
        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "/transformed");

        // Process the code
        CtModel model = launcher.buildModel();

        // Apply the transformation
        new TlsApiFixTransformer().scan(model.getAllTypes());

        // Generate the transformed code
        launcher.process();

        System.out.println("Transformation completed successfully.");
    }

    /**
     * Transformer for fixing Bouncy Castle TLS API issues in Java projects
     * This addresses the removal of org.bouncycastle.crypto.tls package in version 1.67+
     */
    static class TlsApiFixTransformer extends CtScanner {
        @Override
        public void scanCtImport(CtImport ctImport) {
            // Remove imports of the removed TLS package
            if (ctImport.getReference() != null && 
                ctImport.getReference().getQualifiedName().startsWith("org.bouncycastle.crypto.tls")) {
                System.out.println("Removing TLS import: " + ctImport.getReference().getQualifiedName());
                ctImport.delete();
            }
            super.scanCtImport(ctImport);
        }

        @Override
        public <T> void scanCtInvocation(CtInvocation<T> invocation) {
            // Check for usage of the removed TLS API
            if (invocation.getExecutable() != null) {
                String qualifiedName = invocation.getExecutable().getDeclaringType().getQualifiedName();

                // Handle TlsFatalAlert usage
                if (qualifiedName.equals("org.bouncycastle.crypto.tls.TlsFatalAlert")) {
                    System.out.println("Fixing TlsFatalAlert usage: " + invocation.toString());
                    // Replace with IOException (most appropriate replacement)
                    // This is a simplified replacement - in practice you'd need to handle the specific context
                    invocation.replace(invocation.getFactory().Code().createCodeSnippetStatement("throw new IOException(\"TLS alert: " + invocation.getArguments().get(0).toString() + "\")"));
                }
                // Handle AlertDescription usage
                else if (qualifiedName.equals("org.bouncycastle.crypto.tls.AlertDescription")) {
                    System.out.println("Fixing AlertDescription usage: " + invocation.toString());
                    // Replace with appropriate integer values
                    // In practice, you'd need to map the constants to their numeric values
                    String alertName = invocation.toString();
                    if (alertName.contains("bad_record_mac")) {
                        invocation.replace(invocation.getFactory().Code().createCodeSnippetExpression("10")); // 10 is the numeric value for bad_record_mac
                    } else if (alertName.contains("handshake_failure")) {
                        invocation.replace(invocation.getFactory().Code().createCodeSnippetExpression("40")); // 40 is the numeric value for handshake_failure
                    } else {
                        // For other cases, replace with a default value
                        invocation.replace(invocation.getFactory().Code().createCodeSnippetExpression("0"));
                    }
                }
            }
            super.scanCtInvocation(invocation);
        }
    }
}

